import React, { useRef, useState } from "react";
import CalculatorPopup from "./CalculatorPopup";
import { api } from "../api";
import { FiCalculator, FiBell } from "react-icons/fi";

export default function Header() {
  const [name, setName] = useState("Monica");
  const [editing, setEditing] = useState(false);
  const [profilePic, setProfilePic] = useState(null);
  const [calcOpen, setCalcOpen] = useState(false);
  const fileInputRef = useRef();

  // Placeholder user profile image or uploaded one
  const profileImgSrc = profilePic
    ? URL.createObjectURL(profilePic)
    : "https://randomuser.me/api/portraits/women/44.jpg";

  const handleNameSave = async () => {
    setEditing(false);
    // PATCH request to update profile name
    try {
      const token = localStorage.getItem("token");
      await api.patch(
        "/user/profile",
        { displayName: name },
        {
          headers: { Authorization: `Bearer ${token}` },
        }
      );
    } catch (err) {
      alert("Failed to update name.");
    }
  };

  const handleImageUpload = async (e) => {
    if (e.target.files && e.target.files[0]) {
      setProfilePic(e.target.files[0]);
      // Upload to backend
      const token = localStorage.getItem("token");
      const formData = new FormData();
      formData.append("file", e.target.files[0]);
      try {
        const uploadRes = await api.post("/upload/screenshot", formData, {
          headers: {
            "Content-Type": "multipart/form-data",
            Authorization: `Bearer ${token}`,
          },
        });
        const url = uploadRes.data.url;
        // Update user profilePicture URL
        await api.patch(
          "/user/profile",
          { profilePicture: url },
          {
            headers: { Authorization: `Bearer ${token}` },
          }
        );
      } catch {
        alert("Image upload failed.");
      }
    }
  };

  return (
    <header
      style={{
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        background: "#fff",
        borderRadius: "0 0 24px 24px",
        padding: "20px 30px",
        boxShadow: "0 2px 8px #eee",
      }}
    >
      <div style={{ display: "flex", alignItems: "center", gap: "18px" }}>
        <div style={{ position: "relative", width: 42, height: 42 }}>
          <img
            src={profileImgSrc}
            alt="Profile"
            style={{
              width: 42,
              height: 42,
              borderRadius: "50%",
              objectFit: "cover",
              cursor: "pointer",
            }}
            onClick={() => fileInputRef.current.click()}
            title="Click to change photo"
          />
          <input
            type="file"
            accept="image/*"
            ref={fileInputRef}
            style={{ display: "none" }}
            onChange={handleImageUpload}
          />
        </div>
        <div>
          {editing ? (
            <input
              value={name}
              onChange={(e) => setName(e.target.value)}
              onBlur={handleNameSave}
              style={{
                fontWeight: 700,
                fontSize: 17,
                border: "1px solid #eee",
                borderRadius: 4,
                padding: "2px 8px",
              }}
              autoFocus
            />
          ) : (
            <div style={{ fontWeight: 700, fontSize: 17 }}>
              Hello{" "}
              <span
                onClick={() => setEditing(true)}
                style={{ color: "#5D5FEF", cursor: "pointer" }}
              >
                {name}!
              </span>
            </div>
          )}
          <div style={{ fontSize: 12, color: "#9b9b9b" }}>Welcome back</div>
        </div>
      </div>
      <div style={{ display: "flex", gap: "22px", alignItems: "center" }}>
        <button
          onClick={() => setCalcOpen(true)}
          style={{
            background: "none",
            border: "none",
            cursor: "pointer",
            padding: 0,
            display: "flex",
            alignItems: "center",
          }}
          title="Calculator"
        >
          <FiCalculator size={25} />
        </button>
        <button
          style={{
            background: "none",
            border: "none",
            cursor: "pointer",
            padding: 0,
            display: "flex",
            alignItems: "center",
          }}
          title="Notifications"
          // onClick={...} // Add functionality if needed
        >
          <FiBell size={25} />
        </button>
        <CalculatorPopup open={calcOpen} onClose={() => setCalcOpen(false)} />
      </div>
    </header>
  );
}
